// Validate presence of email and company
const items = $input.all();
return items.map(item => {
  const { email, company } = item.json;
  const valid = !!(email && company);
  return {
    json: {
      ...item.json,
      validation: {
        valid,
        message: valid ? 'OK' : 'Missing required email or company'
      }
    }
  };
});

// Basic lead-scoring example. Adjust weights as needed.
const items = $input.all();
return items.map(item => {
  const data = item.json;
  let score = 0;

  if (data.company) score += 20;

  const employees = data.enrichment?.company?.metrics?.employees || data.enrichment?.company?.employees;
  if (employees) {
    if (employees > 500) score += 30;
    else if (employees > 100) score += 20;
    else score += 10;
  }

  if (data.enrichment?.person?.linkedin?.handle) score += 20;
  if (/^.+@.+\..+$/.test(data.email)) score += 10;

  return {
    json: {
      ...data,
      leadScore: score
    }
  };
});

const items = $input.all();
return items.map(item => {
  const fileName = `lead_${Date.now()}_qualified.json`;
  return {
    json: {
      ...item.json,
      fileName,
      fileContent: JSON.stringify(item.json, null, 2)
    }
  };
});

